Bash(powershell -Command "
\\$dirs = @\(\\$env:USERPROFILE+'\\Desktop',\\$env:USERPROFILE+'\\Documents',\\$env:USERPROFILE+'\\Downloads',\\$env:USERPROFILE+'\\Pictures'\)
foreach \(\\$d in \\$dirs\) {
    Get-ChildItem -Path \\$d -Filter '_AAAA_*' -Force -ErrorAction SilentlyContinue | ForEach-Object {
        \\$_.Attributes = 'Normal'; Remove-Item \\$_.FullName -Force
        Write-Host 'Removed: ' \\$_.FullName
    }
}
Write-Host 'Cleanup done'
")

Bash(powershell.exe -NoProfile -NonInteractive -Command "
\\$alertFile = 'D:\\PBL RANS\\rdrs_alerts.json'
Start-Process -FilePath 'C:\\Windows\\System32\\vssadmin.exe' -ArgumentList 'list shadows' -WindowStyle Hidden
Start-Sleep -Seconds 3
\\$alerts = \(Get-Content \\$alertFile -Raw | ConvertFrom-Json\)
\\$vss = @\(\\$alerts | Where-Object { \\$_.EventType -eq 'VssDeletion' }\)
Write-Host 'VSS alerts found:' \\$vss.Count
if \(\\$vss.Count -gt 0\) {
    foreach \(\\$a in \\$vss\) {
        Write-Host 'AlertId:' \\$a.AlertId 'Risk:' \\$a.RiskLabel 'Process:' \\$a.ProcessName 'Indicators:' \(\\$a.Indicators -join ','\)
    }
} else {
    Write-Host 'No VSS alert yet - WMI subscription requires the watcher to be running elevated'
    Write-Host 'Total alerts in log:' \\$alerts.Count
    Write-Host 'Most recent alert:'
    \\$alerts[-1] | Select-Object AlertId,Timestamp,EventType,RiskLabel | Format-List
}
" 2>&1)

